45.         exit 2
46.     }
47. 
48.     # Prefer aggregate numerator/denominator attributes when present.
49.     if ($null -ne $cobertura.coverage.'lines-covered' -and $null -ne $cobertura.coverage.'lines-valid') {
50.         $totalLinesCovered += [double]$cobertura.coverage.'lines-covered'
51.         $totalLinesValid += [double]$cobertura.coverage.'lines-valid'
52.     } elseif ($cobertura.coverage.'line-rate') {
