57.         $totalBranchesValid += [double]$cobertura.coverage.'branches-valid'
58.     } elseif ($cobertura.coverage.'branch-rate') {
59.         $fallbackBranchRates.Add([double]$cobertura.coverage.'branch-rate')
60.     }
61. 
62.     foreach ($package in $cobertura.coverage.packages.package) {
63.         foreach ($class in $package.classes.class) {
64.             $className = $class.name
65.             $fileName  = $class.filename
66. 
67.             foreach ($method in $class.methods.method) {
68.                 $key = "$className|$($method.name)|$($method.signature)|$fileName"
69. 
70.                 # Cyclomatic complexity is stored as an XML attribute in Cobertura format
71.                 $complexity = if ($null -ne $method.complexity) { [int]$method.complexity } else { 1 }
72.                 if ($complexity -lt 1) { $complexity = 1 }
73. 
74.                 if (-not $methodMap.ContainsKey($key)) {
